using System; using System.Collections.Generic; using System.Linq; using UnityEngine; namespace DungeonSlash { public sealed class PerkChoiceView : MonoBehaviour { [SerializeField] private GameObject panel; [SerializeField] private List<PerkChoiceItem> items = new(); public void Configure(GameObject newPanel, IEnumerable<PerkChoiceItem> newItems) { panel = newPanel; items = newItems.ToList(); } public void Show(IReadOnlyList<PerkData> perks, Action<PerkData> selected) { panel.SetActive(true); for (var i = 0; i < items.Count; i++) items[i].gameObject.SetActive(i < perks.Count); for (var i = 0; i < perks.Count; i++) items[i].Bind(perks[i], selected); } public void Hide() => panel.SetActive(false); } }
